// RH组装 nodeInfoList（兼容 n8n 1.123.x）
// 当前节点：Run Once for All Items

// 1) Merge 输出（当前输入）里已经有 publicUrl（图 or 音）
// 但你这里需要同时拿到 “音频网址转换”和“图片网址转换” 两个节点的 publicUrl
const apiKey = $node["整理数据"].json?.runninghub_key || $node["整理数据"].item?.json?.runninghub_key;

// 直接从两个转换节点取 URL（最稳定）
const audioUrl = $node["音频网址转换"].json?.publicUrl;
const imageUrl = $node["图片网址转换"].json?.publicUrl;

// workflowId 写死也行，但建议从整理数据/参数里统一管理
const workflowId = "2022355218020704258";

if (!apiKey) throw new Error("缺 runninghub_key（节点：整理数据.runninghub_key）");
if (!audioUrl) throw new Error("缺 音频 publicUrl（节点：音频网址转换.publicUrl）");
if (!imageUrl) throw new Error("缺 图片 publicUrl（节点：图片网址转换.publicUrl）");

// ⚠️前提：RunningHub 工作流的 audio/image 字段支持 URL 输入
const nodeInfoList = [
  { nodeId: "238", fieldName: "audio", fieldValue: String(audioUrl) },
  { nodeId: "221", fieldName: "image", fieldValue: String(imageUrl) },
];

return [{
  apiKey,
  workflowId,
  nodeInfoList,
}];

const body = $node["Webhook"].json.body || {};

const record_id = body.record_id;
const app_token = body.app_token;
const app_id = body.app_id;
const app_secret = body.app_secret;

// table_id 从 parseUrl 取（别用 table_link）
const table_id = $node["获取任务表信息"].json.table_id;

if (!record_id || !app_token || !table_id || !app_id || !app_secret) {
  throw new Error("缺参数：record_id/app_token/table_id/app_id/app_secret");
}

// 你的回调入口
const base = "https://hooks.flowonn.com/webhook/rh_task_end";

// 参数名用最短，减少长度
const webhookUrl =
  `${base}?r=${encodeURIComponent(record_id)}` +
  `&a=${encodeURIComponent(app_token)}` +
  `&t=${encodeURIComponent(table_id)}` +
  `&i=${encodeURIComponent(app_id)}` +
  `&s=${encodeURIComponent(app_secret)}`;

return [{
  ...$node["RH组装nodeInfoList"].json,
  webhookUrl
}];

const j = $json;

if (!j.apiKey) throw new Error("缺 apiKey");
if (!j.workflowId) throw new Error("缺 workflowId");
if (!Array.isArray(j.nodeInfoList)) throw new Error("nodeInfoList 必须是数组");
if (!j.webhookUrl) throw new Error("缺 webhookUrl");

// 可选：独占队列才需要；你现在是 plus 显存机，不一定要开
// const usePersonalQueue = false;

return [{
  payload: {
    apiKey: j.apiKey,
    workflowId: String(j.workflowId),
    nodeInfoList: j.nodeInfoList,
    webhookUrl: j.webhookUrl,
    // usePersonalQueue,
    // addMetadata: true, // 需要的话也可以显式写
  }
}];

// ✅ 兼容 n8n 1.123.x：不用 .first()
// ✅ 当前节点 Run Once for All Items：用 $input.first()

const body = $node["Webhook"].json?.body || {};
const baseInfo = $node["获取任务表信息"].json || {}; // parseUrl 输出一般是单条

const record_id = body.record_id;
const app_token = body.app_token;
const table_id = baseInfo.table_id;
const api_key = body.api_key;

if (!record_id || !app_token || !table_id) {
  throw new Error("缺 record_id/app_token/table_id");
}

const item = $input.first();
if (!item?.binary?.audio) {
  throw new Error("缺 binary.audio（检查：下载口播音频 outputPropertyName 是否为 audio）");
}

// 强制英文文件名 + 正确 mime
item.binary.audio.fileName = "voice.mp3";
item.binary.audio.mimeType = "audio/mpeg";

// 输出：带 json 上下文 + binary.audio
return [{
  json: {
    record_id,
    app_token,
    table_id,
    api_key,
    fileName: `dh_voice_${record_id}_${Date.now()}.mp3`,
  },
  binary: {
    audio: item.binary.audio,
  },
}];

// OSSClient 输出里一般会有 name/objectKey（对象 key）
// 同时我们从“音频准备上传参数”回取上下文，保证字段不断链
const ossOut = $json || {};
const ctx = $node["音频准备上传参数"].json || {};

const keyRaw = ossOut.name || ossOut.objectKey || '';
const key = String(keyRaw).replace(/^\/+/, '');

if (!key) throw new Error("OSS 未返回 objectKey/name");

const cdnHost = "https://oss.flowonn.com";
const publicUrl = `${cdnHost}/${encodeURI(key)}`;

return [{
  json: {
    publicUrl,
    record_id: ctx.record_id,
    app_token: ctx.app_token,
    table_id: ctx.table_id,
    api_key: ctx.api_key
  }
}];

